// Normalize syllabus rows: ensure Section, Topic, Subtopics (string)
const items = $input.all();
return items.map(item => {
  const j = item.json;
  const section = j.Section || j.section || '';
  const topic = j.Topic || j.topic || '';
  let subtopics = j.Subtopics ?? j['Sub topics'] ?? j.sub_topics ?? '';
  if (Array.isArray(subtopics)) subtopics = subtopics.join(', ');
  return { json: { Section: section, Topic: topic, Subtopics: String(subtopics) } };
});

