// Merge study material + flashcards + MCQs into one Markdown and prepare for Drive upload
const item = $input.first().json;
const study = item.studyMaterialMarkdown || '';
const flashcards = item.flashcardsMarkdown || '';
const mcqs = item.mcqsMarkdown || '';
const fullMarkdown = [study, '---', '## Flashcards', flashcards, '---', '## MCQs', mcqs].filter(Boolean).join('\n\n');
const topicFileName = (item.Topic || 'topic').replace(/\s+/g, '_').replace(/[^a-zA-Z0-9_\-]/g, '');
const buffer = Buffer.from(fullMarkdown, 'utf8');
const binaryData = await this.helpers.prepareBinaryData(buffer, `${topicFileName}.md`, 'text/markdown');
return [{ json: { topicFileName, fullMarkdown }, binary: { data: binaryData } }];
